DROP TABLE IF EXISTS `visit_tidak_kunjungan_mr`;
CREATE TABLE `visit_tidak_kunjungan_mr` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `periode` varchar(10) NOT NULL,
  `week` varchar(10) NOT NULL,
  `id_peg` int(11) DEFAULT NULL,
  `id_ff` varchar(15) DEFAULT NULL,
  `nama` varchar(200) DEFAULT NULL,
  `divisi` varchar(50) DEFAULT NULL,
  `tanggal` date DEFAULT NULL,
  `alasan` varchar(50) DEFAULT NULL,
  `keterangan` varchar(250) DEFAULT NULL,
  PRIMARY KEY (`id`),
  UNIQUE KEY `id_peg` (`id_peg`,`tanggal`)
) ENGINE=InnoDB AUTO_INCREMENT=13901 DEFAULT CHARSET=utf8 COLLATE=utf8_general_ci;

